function esc(v){return String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function businessParts(date=new Date()){return Object.fromEntries(new Intl.DateTimeFormat('en-CA',{timeZone:BUSINESS_TIME_ZONE,year:'numeric',month:'2-digit',day:'2-digit'}).formatToParts(date).filter(p=>p.type!=='literal').map(p=>[p.type,p.value]))}
function businessDayKey(date=new Date()){const p=businessParts(date);return `${p.year}-${p.month}-${p.day}`}
function shiftDayKey(key,days){const d=new Date(`${key}T12:00:00Z`);d.setUTCDate(d.getUTCDate()+days);return d.toISOString().slice(0,10)}
function businessBoundary(key){const [year,month,day]=key.split('-').map(Number),guess=Date.UTC(year,month-1,day);const parts=new Intl.DateTimeFormat('en-US',{timeZone:BUSINESS_TIME_ZONE,year:'numeric',month:'numeric',day:'numeric',hour:'numeric',minute:'numeric',second:'numeric',hourCycle:'h23'}).formatToParts(new Date(guess)),values=Object.fromEntries(parts.filter(p=>p.type!=='literal').map(p=>[p.type,Number(p.value)])),asUtc=Date.UTC(values.year,values.month-1,values.day,values.hour,values.minute,values.second);return new Date(guess-(asUtc-guess))}
function today(){return businessDayKey()}
