async function loadData({quiet=false}={}){
  if(!db){setSync('线上配置缺失','error');return}
  if(!quiet)setSync('正在同步…','saving');
  const [projectsRes,trendsRes,relationsRes,metricsRes,observationsRes,tasksRes,activityRes,gateDefinitionsRes,gatesRes,templateGatesRes,historyRes,experimentsRes,templatesRes,templateStatsRes]=await Promise.all([
    db.from('projects').select('*').order('created_at',{ascending:false}),
    db.from('trends').select('*').order('created_at',{ascending:false}),
    db.from('project_trends').select('*').order('created_at',{ascending:true}),
    db.from('metrics').select('*').order('position',{ascending:true}),
    db.from('metric_observations').select('*').order('measured_at',{ascending:false}).limit(2000),
    db.from('tasks').select('*').order('created_at',{ascending:true}),
    db.from('activity_logs').select('*').order('created_at',{ascending:false}).limit(1000),
    db.from('stage_gate_definitions').select('*').order('stage',{ascending:true}).order('position',{ascending:true}),
    db.from('project_stage_gates').select('*').order('created_at',{ascending:true}),
    db.from('project_template_gates').select('*').order('stage',{ascending:true}),
    db.from('stage_history').select('*').order('created_at',{ascending:false}).limit(1000),
    db.from('validation_experiments').select('*').order('created_at',{ascending:false}).limit(1000),
    db.from('validation_templates').select('*').order('updated_at',{ascending:false}),
    db.rpc('template_usage_stats')
  ]);
  const failure=[projectsRes,trendsRes,relationsRes,metricsRes,observationsRes,tasksRes,activityRes,gateDefinitionsRes,gatesRes,templateGatesRes,historyRes,experimentsRes,templatesRes,templateStatsRes].find(r=>r.error);
  if(failure){setSync('同步失败','error');notice(`线上数据读取失败：${failure.error.message}`);return}
  deletedProjects=projectsRes.data.filter(p=>p.deleted_at);
  const activeRows=projectsRes.data.filter(p=>!p.deleted_at);
  state.projects=activeRows.map(p=>({
    ...p,
    metrics:metricsRes.data.filter(m=>m.project_id===p.id).map(m=>({...m,observations:observationsRes.data.filter(o=>o.metric_id===m.id).sort((a,b)=>new Date(b.measured_at)-new Date(a.measured_at))})),
    tasks:tasksRes.data.filter(t=>t.project_id===p.id),
    gates:gatesRes.data.filter(g=>g.project_id===p.id),
    templateGates:templateGatesRes.data.filter(g=>g.project_id===p.id),
    history:historyRes.data.filter(h=>h.project_id===p.id),
    experiments:experimentsRes.data.filter(e=>e.project_id===p.id).sort((a,b)=>b.round_no-a.round_no)
  }));
  state.relations=relationsRes.data.filter(r=>activeRows.some(p=>p.id===r.project_id));
  state.trends=trendsRes.data.map(t=>{const mappings=state.relations.filter(r=>r.trend_id===t.id);return {...t,mappings,projectIds:mappings.map(r=>r.project_id)}}).filter(t=>t.projectIds.length||isAdmin);
  state.activity=activityRes.data.map(a=>({...a,at:businessDayKey(new Date(a.created_at))}));
  state.gateDefinitions=gateDefinitionsRes.data;
  state.templates=templatesRes.data.map(t=>({...t,...(templateStatsRes.data.find(s=>s.template_id===t.id)||{usage_count:0,success_count:0})}));
  lastDataUpdatedAt=new Date();
  renderAll();
  setSync(`已同步 · ${new Date().toLocaleTimeString('zh-CN',{timeZone:BUSINESS_TIME_ZONE,hour:'2-digit',minute:'2-digit'})}`,'online');
}

async function writeLog(projectId,text,type='更新'){
  const {error}=await db.from('activity_logs').insert({project_id:projectId||null,text,type,actor_email:currentUser?.email||ADMIN_EMAIL});
  if(error)throw error;
}

async function mutate(action,successText){
  if(!requireAdmin())return false;
  setSync('正在保存…','saving');
  try{await action();await loadData({quiet:true});if(successText)notice(successText);return true}
  catch(error){setSync('保存失败','error');notice(`保存失败：${error.message||error}`);return false}
}

