  $('#topUserInitial').textContent=isAdmin?'ML':'访';$('#topUserName').textContent=isAdmin?'曼斯菲尔德':'公开访客';$('#topUserRole').textContent=isAdmin?'管理员 · 可编辑':'访客 · 只读查看';$('#topUserEmail').textContent=isAdmin?currentUser.email:'无需登录即可查看';
