function renderCycle(){const p=businessParts(),year=Number(p.year),month=Number(p.month),quarter=Math.floor((month-1)/3)+1,quarterStartMonth=(quarter-1)*3+1,currentKey=`${p.year}-${p.month}-${p.day}`,startKey=`${year}-${String(quarterStartMonth).padStart(2,'0')}-01`,week=Math.floor((new Date(`${currentKey}T12:00:00Z`)-new Date(`${startKey}T12:00:00Z`))/604800000)+1,totalWeeks=Math.ceil((new Date(Date.UTC(year,quarter*3,1))-new Date(Date.UTC(year,quarterStartMonth-1,1)))/604800000);$('#currentQuarter').textContent=`${year} · Q${quarter}`;$('#currentQuarterWeek').textContent=`季度第 ${week} / ${totalWeeks} 周`;$('#businessTimezone').textContent=`业务时区 · ${BUSINESS_TIME_ZONE}`}

function renderCounts(){
  const stats=decisionStats();
  const values={activeProjects:stats.active.current,weeklyConclusions:stats.conclusions.current,pendingDecisions:stats.pending.current,riskProjects:stats.risk.current};
  Object.entries(values).forEach(([id,value])=>{$(`#${id}`).textContent=String(value).padStart(2,'0')});
  [['activeProjectsDelta',stats.active],['weeklyConclusionsDelta',stats.conclusions],['pendingDecisionsDelta',stats.pending],['riskProjectsDelta',stats.risk]].forEach(([id,data])=>renderDelta(id,data.current-data.previous));
  const updatedAt=(lastDataUpdatedAt||new Date()).toLocaleTimeString('zh-CN',{timeZone:BUSINESS_TIME_ZONE,hour:'2-digit',minute:'2-digit'});$('#decisionWeekRange').textContent=`本周 ${formatShortDate(stats.weekStart)} — ${formatShortDate(stats.weekEnd)} · ${BUSINESS_TIME_ZONE}`;$('#decisionUpdatedAt').textContent=`最近更新 ${updatedAt}`;renderCycle();
  $('#riskIssueCount').textContent=String(riskIssues().length);
  $$('[data-command-filter]').forEach(card=>{const active=selectedCommandFilter===card.dataset.commandFilter,alert=Number(card.querySelector('strong').textContent)>0;card.classList.toggle('active',active);card.classList.toggle('has-alert',alert);card.setAttribute('aria-pressed',String(active))});
  renderStageFunnel();
}

function stageEnteredAt(p){
  const history=p.history?.find(h=>h.to_stage===p.stage);
  if(history){const value=new Date(history.created_at);if(Number.isFinite(value.getTime()))return value}
  const marker=`调整至「${stages[p.stage]}」`;
  const entry=state.activity.find(a=>a.project_id===p.id&&a.type==='阶段流转'&&a.text.includes(marker));
  const value=new Date(entry?.created_at||p.created_at);
  return Number.isFinite(value.getTime())?value:new Date();
}
function gateDefinitions(stage){return state.gateDefinitions.filter(g=>g.stage===stage)}
function gateStatus(p,stage=p.stage){const definitions=gateDefinitions(stage),completed=new Set(p.gates.filter(g=>g.stage===stage&&g.completed).map(g=>g.gate_key)),missing=definitions.filter(g=>g.required&&!completed.has(g.gate_key));return {definitions,completed,missing,done:definitions.filter(g=>completed.has(g.gate_key)).length,total:definitions.length}}
function experimentComplete(e){return Boolean(e.completed_at&&e.conclusion?.trim()&&e.decision)}
function hasCompletedStageExperiment(p,stage=p.stage){return p.experiments.some(e=>e.stage===stage&&experimentComplete(e))}
function latestObservation(m){return m.observations?.[0]||null}
function metricStatus(m){const o=latestObservation(m);if(!o||!Number.isFinite(Number(o.value))||Number(o.sample_size)<=0)return '数据不足';const value=Number(o.value),target=Number(m.target_value),baseline=Number(m.baseline_value),passed=m.comparison_operator==='>'?value>target:m.comparison_operator==='>='?value>=target:m.comparison_operator==='<'?value<target:value<=target;if(passed)return '达标';const tolerance=Math.max(Math.abs(target-baseline)*.2,Math.abs(target)*.1,.0001),near=['>','>='].includes(m.comparison_operator)?value>=target-tolerance:value<=target+tolerance;return near?'接近目标':'未达标'}
function advanceRequirements(p){const missing=gateStatus(p).missing.map(g=>({type:'gate',label:g.label}));(p.templateGates||[]).filter(g=>g.stage===p.stage&&!g.completed).forEach(g=>missing.push({type:'gate',label:`模板门槛：${g.label}`}));if(p.stage<4&&!hasCompletedStageExperiment(p))missing.push({type:'experiment',label:`完成至少一轮「${stages[p.stage]}」验证实验，并填写结论与最终决策`});p.metrics.filter(m=>m.stage===p.stage&&m.is_key&&metricStatus(m)!=='达标').forEach(m=>missing.push({type:'metric',label:`关键指标「${m.name}」当前为“${metricStatus(m)}”，需达到目标后推进`}));return missing}
function stageFunnelStats(){
  const total=state.projects.length;
  return stages.map((_,stage)=>{const projects=state.projects.filter(p=>p.stage===stage),dwell=projects.map(projectDwell);return {count:projects.length,share:total?Math.round(projects.length/total*100):0,average:dwell.length?dwell.reduce((sum,n)=>sum+n,0)/dwell.length:0,overdue:projects.filter(p=>p.tasks.some(t=>!t.done&&t.due<today())).length}});
}
function renderStageFunnel(){
  const stats=stageFunnelStats();
  $('#allCount').textContent=String(state.projects.length).padStart(2,'0');
  stats.forEach((item,i)=>{$(`#stage${i}Count`).textContent=String(item.count).padStart(2,'0');$(`#stage${i}Share`).textContent=`${item.share}%`;$(`#stage${i}Dwell`).textContent=`${item.average.toFixed(1)} 天`;$(`#stage${i}Overdue`).textContent=String(item.overdue);$(`#stage${i}Bar`).style.width=`${item.share}%`;const tab=$(`.stage-tab[data-stage="${i}"]`);tab.classList.toggle('has-overdue',item.overdue>0)});
}

function startOfWeek(date=new Date()){const key=businessDayKey(date),calendar=new Date(`${key}T12:00:00Z`),offset=(calendar.getUTCDay()+6)%7;return businessBoundary(shiftDayKey(key,-offset))}
function endOfWeek(start){return businessBoundary(shiftDayKey(businessDayKey(start),7))}
function inRange(value,start,end){const time=new Date(value).getTime();return Number.isFinite(time)&&time>=start.getTime()&&time<end.getTime()}
function formatShortDate(date){return date.toLocaleDateString('zh-CN',{timeZone:BUSINESS_TIME_ZONE,month:'numeric',day:'numeric'})}
function formatBusinessDateTime(value,options={}){return new Date(value).toLocaleString('zh-CN',{timeZone:BUSINESS_TIME_ZONE,...options})}
function renderDelta(id,delta){const node=$(`#${id}`);node.textContent=delta===0?'与上周持平':`较上周 ${delta>0?'+':''}${delta}`;node.classList.toggle('is-up',delta>0);node.classList.toggle('is-down',delta<0)}
function conclusionLogs(start,end){return state.activity.filter(a=>['指标','阶段流转','趋势结论','阶段结论','验证结论'].includes(a.type)&&inRange(a.created_at,start,end))}
function isPendingConclusion(a){return ['指标','趋势结论','阶段结论'].includes(a.type)||(a.type==='验证结论'&&/(进入下一阶段|规模化)/.test(a.text))}
function pendingDecisionIds(end=new Date()){return new Set(state.projects.filter(p=>{const logs=state.activity.filter(a=>a.project_id===p.id&&new Date(a.created_at)<end);const conclusion=logs.find(isPendingConclusion);const decision=logs.find(a=>a.type==='阶段流转');return conclusion&&(!decision||new Date(conclusion.created_at)>new Date(decision.created_at))}).map(p=>p.id))}
function daysBetween(from,to=new Date()){const fromKey=/^\d{4}-\d{2}-\d{2}$/.test(String(from))?String(from):businessDayKey(new Date(from)),toKey=/^\d{4}-\d{2}-\d{2}$/.test(String(to))?String(to):businessDayKey(new Date(to));return Math.max(0,Math.floor((new Date(`${toKey}T12:00:00Z`)-new Date(`${fromKey}T12:00:00Z`))/86400000))}
function nextTask(p){return p.tasks.filter(t=>!t.done).sort((a,b)=>String(a.due).localeCompare(String(b.due))||(priorityRank[b.priority]||2)-(priorityRank[a.priority]||2))[0]||null}
function riskIssues(projects=state.projects,asOf=new Date()){
  const day=businessDayKey(asOf),soonDay=shiftDayKey(day,3),pending=pendingDecisionIds(new Date(asOf.getTime()+1));
  return projects.flatMap(p=>{const items=[],dwell=daysBetween(stageEnteredAt(p),asOf),add=(type,level,owner,since,action,ref='')=>items.push({id:`${p.id}:${type}:${ref}`,projectId:p.id,project:p.name,type,level,owner:owner||p.owner,duration:Math.max(0,daysBetween(since,asOf)),action});
    p.tasks.filter(t=>!t.done).forEach(t=>{if(t.due<day)add('逾期任务','高',t.owner,t.due,'立即确认阻塞原因并重排截止时间',t.id);else if(t.due<=soonDay)add('即将到期任务','中',t.owner,t.created_at,'确认交付物与按期完成把握',t.id);if(t.confirmation_status==='pending')add('等待负责人确认','中',t.owner,t.created_at,'负责人确认接单，或重新分配任务',t.id)});
    if(dwell>stageDwellLimits[p.stage])add('阶段停留超时',dwell>stageDwellLimits[p.stage]+7?'高':'中',p.owner,stageEnteredAt(p),'复盘阶段阻塞项并形成推进或终止决策');
    p.metrics.filter(m=>m.stage===p.stage&&m.is_key).forEach(m=>{const status=metricStatus(m),o=latestObservation(m);if(status!=='达标')add('指标未达标',status==='未达标'?'高':'中',p.owner,o?.measured_at||m.created_at,status==='数据不足'?`补充「${m.name}」的有效样本与本期数据`:`补充实验或调整方案，使「${m.name}」达到目标`,m.id)});p.metrics.filter(m=>m.stage===p.stage).forEach(m=>{const o=latestObservation(m);if(!o?.source_name||!o?.source_url)add('缺少数据来源','中',p.owner,o?.measured_at||m.created_at,`补齐「${m.name}」的数据来源名称与链接`,m.id)});
    if(pending.has(p.id))add('等待管理层决策','高',p.owner,state.activity.find(a=>a.project_id===p.id&&isPendingConclusion(a))?.created_at||p.updated_at,'管理层确认继续、调整、暂停或终止');
    return items});
}
function riskProjectIds(cutoff=today()){const date=new Date(businessBoundary(shiftDayKey(cutoff,1)).getTime()-1);return new Set(riskIssues(state.projects,date).map(i=>i.projectId))}
function projectHealth(p){const issues=riskIssues([p]);return issues.some(i=>i.level==='高')?'风险':issues.length?'关注':'健康'}
function healthClass(value){return value==='风险'?'risk':value==='关注'?'watch':'healthy'}
function decisionStats(){
  const weekStart=startOfWeek(),weekEnd=endOfWeek(weekStart),previousStart=businessBoundary(shiftDayKey(businessDayKey(weekStart),-7));
  const pendingNow=pendingDecisionIds(),pendingPrevious=pendingDecisionIds(weekStart),riskNow=riskProjectIds(),riskPrevious=riskProjectIds(businessDayKey(weekStart));
  const completedValidations=(start,end)=>state.projects.flatMap(p=>p.experiments||[]).filter(e=>e.completed_at&&inRange(e.completed_at,start,end)).length;
  return {weekStart,weekEnd:new Date(weekEnd.getTime()-1),pendingIds:pendingNow,riskIds:riskNow,
    active:{current:state.projects.length,previous:state.projects.filter(p=>new Date(p.created_at)<weekStart).length},
    conclusions:{current:completedValidations(weekStart,weekEnd),previous:completedValidations(previousStart,weekStart)},
    pending:{current:pendingNow.size,previous:pendingPrevious.size},
    risk:{current:riskNow.size,previous:riskPrevious.size}};
}

function projectDwell(p){return daysBetween(stageEnteredAt(p))}
function projectRiskRank(p){return ({风险:3,关注:2,健康:1})[projectHealth(p)]}
function filtered(){const stats=decisionStats(),commandIds=selectedCommandFilter==='risk'?stats.riskIds:stats.pendingIds;let items=state.projects.filter(p=>{const related=trendsFor(p.id),text=`${p.name} ${p.intro} ${p.category} ${p.subcategory} ${p.owner} ${related.map(t=>t.name).join(' ')}`.toLowerCase(),commandMatch=!selectedCommandFilter||commandIds.has(p.id),trendMatch=!selectedTrend||related.some(t=>t.id===selectedTrend),health=projectHealth(p),overdue=p.tasks.some(t=>!t.done&&t.due<today());return commandMatch&&(selectedStage==='all'||p.stage===Number(selectedStage))&&trendMatch&&text.includes(searchTerm.toLowerCase())&&(!projectFilters.category||p.category===projectFilters.category)&&(!projectFilters.stage||p.stage===Number(projectFilters.stage))&&(!projectFilters.owner||p.owner===projectFilters.owner)&&(!projectFilters.health||health===projectFilters.health)&&(!projectFilters.flag||(projectFilters.flag==='overdue'?overdue:stats.pendingIds.has(p.id)))});return items.sort((a,b)=>projectFilters.sort==='due'?String(nextTask(a)?.due||'9999').localeCompare(String(nextTask(b)?.due||'9999')):projectFilters.sort==='risk'?projectRiskRank(b)-projectRiskRank(a):projectFilters.sort==='dwell'?projectDwell(b)-projectDwell(a):new Date(b.updated_at)-new Date(a.updated_at))}

function renderProjects(){
  const items=filtered();
  $('#projectRows').innerHTML=items.map(p=>{const task=nextTask(p),health=projectHealth(p),metric=p.metrics.find(m=>m.stage===p.stage&&m.is_key),status=metric?metricStatus(metric):'数据不足',overdue=task&&task.due<today();return `<article class="project-row" tabindex="0" data-project="${p.id}" role="row"><div class="project-name"><span class="project-dot" style="background:${stageColors[p.stage]}"></span><div><b>${esc(p.name)}</b><small>${esc(p.intro)}</small><span class="mobile-taxonomy">${esc(p.category||'未分类')} · ${esc(p.subcategory||'待补充')}</span></div></div><div class="stage-cell"><span class="stage-pill" style="--stage:${stageColors[p.stage]}">${stages[p.stage]}</span><small class="cell-muted">停留 ${projectDwell(p)} 天 · ${p.progress}%</small></div><div><span class="health-pill ${healthClass(health)}">${health}</span><small class="cell-muted">${riskIssues([p]).length} 个问题</small></div><div class="core-metric-cell"><b>${esc(metric?.name||'尚未设关键指标')}</b><span class="metric-status ${metricStatusClass(status)}">${esc(status)}</span></div><div class="owner-cell">${esc(p.owner)}</div><div class="next-cell"><b>${esc(task?.title||'暂无未完成任务')}</b><small class="${overdue?'is-overdue':''}">${task?`${esc(task.priority||'中')}优先 · ${esc(task.due)}`:'请添加下一步任务'}</small></div></article>`}).join('');
  $('#emptyState').hidden=Boolean(items.length);
  const hasFilter=selectedStage!=='all'||selectedTrend||selectedCommandFilter||searchTerm||Object.values(projectFilters).some((v,i)=>i<5&&v);
  $('#emptyTitle').textContent=hasFilter?'未找到匹配的项目':'暂无进行中的项目';
  $('#emptyCopy').textContent=hasFilter?'尝试切换阶段，或清除当前筛选。':'管理员创建第一个项目后，所有访问者都能在这里看到最新进展。';
  const selectedTrendRecord=state.trends.find(t=>t.id===selectedTrend),clues=[];if(selectedCommandFilter)clues.push(selectedCommandFilter==='decision'?'「待决策项目」':'「风险项目」');if(selectedStage!=='all')clues.push(`「${stages[selectedStage]}」阶段`);if(selectedTrendRecord)clues.push(`趋势「${selectedTrendRecord.name}」`);if(searchTerm)clues.push(`搜索「${searchTerm}」`);
  $('#filterNote').textContent=clues.length?`当前显示 ${clues.join(' · ')}的 ${items.length} 个项目`:`当前显示 ${items.length} 个项目 · 筛选与排序会保留在网址中`;
}

function renderTrends(){
  const heading=$('#trends .panel-head h2');let count=$('.panel-count',heading.parentElement);if(!count){count=document.createElement('span');count.className='panel-count';heading.insertAdjacentElement('afterend',count)}count.textContent=`${state.trends.length} 条趋势`;
  $('#trendList').innerHTML=state.trends.length?state.trends.map(t=>{const names=t.projectIds.map(id=>project(id)?.name).filter(Boolean),summary=names.length<=2?names.join('、'):`${names.slice(0,2).join('、')} 等 ${names.length} 个项目`;return `<article class="trend-card-shell"><button class="trend-card ${selectedTrend===t.id?'selected':''}" data-trend="${t.id}" type="button"><div class="trend-card-top"><b># ${esc(t.name)}</b><span class="trend-score">${esc(t.growth)}</span></div><p>${esc(t.source_platform)} · ${esc(t.volume)} · 关联 ${esc(summary||'待关联')}</p><small>${esc(t.status)} · 可信度 ${esc(t.confidence)}</small></button>${isAdmin?`<button class="trend-edit" type="button" data-edit-trend="${t.id}">维护</button>`:''}</article>`}).join(''):'<p class="empty-inline">暂无趋势记录。管理员可以从第一个市场信号开始建立项目关系。</p>';
}

function renderFilterOptions(){
  const keep=(id,values,placeholder)=>{const node=$(`#${id}`),value=node.value;node.innerHTML=`<option value="">${placeholder}</option>${values.map(v=>`<option value="${esc(v)}">${esc(v)}</option>`).join('')}`;node.value=value};
  keep('filterCategory',[...new Set(state.projects.map(p=>p.category).filter(Boolean))].sort(),'全部类别');
  keep('filterOwner',[...new Set(state.projects.map(p=>p.owner).filter(Boolean))].sort(),'全部负责人');
  const stageNode=$('#filterStage'),stageValue=stageNode.value;stageNode.innerHTML=`<option value="">全部阶段</option>${stages.map((v,i)=>`<option value="${i}">${v}</option>`).join('')}`;stageNode.value=stageValue;
}
function renderRiskCenter(){const all=riskIssues(),level=$('#riskLevelFilter').value,owner=$('#riskOwnerFilter').value,owners=[...new Set(all.map(i=>i.owner).filter(Boolean))].sort(),ownerNode=$('#riskOwnerFilter'),old=ownerNode.value;ownerNode.innerHTML=`<option value="">全部负责人</option>${owners.map(v=>`<option>${esc(v)}</option>`).join('')}`;ownerNode.value=old;const items=all.filter(i=>(!level||i.level===level)&&(!owner||i.owner===owner));$('#riskSummary').textContent=`${new Set(all.map(i=>i.projectId)).size} 个风险项目 · ${all.length} 个具体问题`;$('#riskList').innerHTML=items.length?items.map(i=>`<article class="risk-item level-${i.level}"><div class="risk-item-head"><span>${esc(i.type)}</span><em>${esc(i.level)}风险</em></div><button type="button" data-risk-project="${i.projectId}">${esc(i.project)} →</button><dl><div><dt>负责人</dt><dd>${esc(i.owner)}</dd></div><div><dt>持续时间</dt><dd>${i.duration} 天</dd></div></dl><p><b>建议动作</b>${esc(i.action)}</p></article>`).join(''):'<div class="risk-empty"><b>当前没有匹配的风险</b><span>问题解决后会自动从这里移除。</span></div>'}
function templateLines(value){return Array.isArray(value)?value.map(v=>typeof v==='string'?v:(v.title||v.name||JSON.stringify(v))).join('、'):'—'}
function renderTemplates(){const selectOptions=state.templates.map(t=>`<option value="${t.id}">${esc(t.name)} · v${t.version}</option>`).join('');$('#creationTemplate').innerHTML=`<option value="">请选择模板</option>${selectOptions}`;$('#templateList').innerHTML=state.templates.length?state.templates.map(t=>{const count=Number(t.usage_count||0),success=Number(t.success_count||0),rate=count?Math.round(success/count*100):0;return `<article class="template-card"><div class="template-card-head"><span>v${t.version} · ${esc(t.opportunity_type)}</span><b>${esc(t.name)}</b></div><p>${esc(t.target_audience)}</p><dl><div><dt>验证方式</dt><dd>${esc(templateLines(t.recommended_methods))}</dd></div><div><dt>预计周期</dt><dd>${esc(t.estimated_cycle)}</dd></div><div><dt>使用 / 成功率</dt><dd>${count} 次 · ${rate}%</dd></div></dl><div class="template-card-foot"><small>${esc(t.created_by)} · ${new Date(t.updated_at).toLocaleDateString('zh-CN',{timeZone:BUSINESS_TIME_ZONE})}</small><button type="button" data-use-template="${t.id}">从模板创建 →</button></div>${count?`<details><summary>参考历史项目</summary>${state.projects.filter(p=>p.template_id===t.id).map(p=>`<button type="button" data-template-project="${p.id}">${esc(p.name)} · ${stages[p.stage]}</button>`).join('')}</details>`:''}</article>`}).join(''):'<div class="template-empty"><b>暂无验证模板</b><span>规模转化阶段的项目可以一键提炼为团队模板。</span></div>'}

function renderTrash(){
  $('#trashList').innerHTML=deletedProjects.length?deletedProjects.map(p=>`<div class="trash-item"><div><b>${esc(p.name)}</b><small>删除于 ${new Date(p.deleted_at).toLocaleString('zh-CN',{timeZone:BUSINESS_TIME_ZONE})}</small></div><button type="button" data-restore-project="${p.id}">恢复项目</button></div>`).join(''):'<p class="empty-inline">暂无已删除项目。</p>';
}

function renderAll(){
  renderFilterOptions();renderCounts();renderProjects();renderTrends();renderTemplates();renderTrash();renderAuth();
  if($('#riskDrawer').classList.contains('open'))renderRiskCenter();
}

function metricOperatorLabel(value){return ({'>':'大于','>=':'大于等于','<':'小于','<=':'小于等于'})[value]||value}
function metricStatusClass(status){return ({'达标':'passed','接近目标':'near','未达标':'failed','数据不足':'insufficient'})[status]||'insufficient'}
function metricTrendSvg(m){const items=[...(m.observations||[])].reverse(),values=items.map(o=>Number(o.value)).filter(Number.isFinite);if(!values.length)return '<div class="metric-no-trend">暂无周期数据</div>';const min=Math.min(...values),max=Math.max(...values),range=max-min||1,points=values.map((value,i)=>`${values.length===1?70:4+i*132/(values.length-1)},${28-(value-min)/range*22}`).join(' '),latest=values.at(-1),previous=values.length>1?values.at(-2):null,change=previous===null?'首期数据':`较上期 ${latest-previous>=0?'+':''}${(latest-previous).toLocaleString('zh-CN')} ${m.unit}`;return `<div class="metric-trend"><svg viewBox="0 0 140 34" role="img" aria-label="${esc(m.name)} 共 ${values.length} 期变化趋势"><polyline points="${points}"></polyline>${points.split(' ').map(point=>{const [cx,cy]=point.split(',');return `<circle cx="${cx}" cy="${cy}" r="2.2"></circle>`}).join('')}</svg><span>${items.length} 期 · ${esc(change)}</span></div>`}
function metricCard(m,p){const latest=latestObservation(m),status=metricStatus(m),source=latest&&/^https?:\/\//i.test(latest.source_url)?`<a href="${esc(latest.source_url)}" target="_blank" rel="noreferrer">${esc(latest.source_name)} ↗</a>`:esc(latest?.source_name||'暂无来源'),history=(m.observations||[]).slice(0,3).map(o=>`<li><time>${esc(o.period_start)} — ${esc(o.period_end)}</time><b>${Number(o.value).toLocaleString('zh-CN')} ${esc(m.unit)}</b><span>n=${Number(o.sample_size||0).toLocaleString('zh-CN')}</span></li>`).join('');return `<article class="metric-card ${metricStatusClass(status)}"><div class="metric-card-head"><div><span>${esc(stages[m.stage])}${m.is_key?' · 关键指标':''}</span><h4>${esc(m.name)}</h4></div><em class="metric-status ${metricStatusClass(status)}">${esc(status)}</em></div><div class="metric-current"><strong>${latest?Number(latest.value).toLocaleString('zh-CN'):'—'} <small>${esc(m.unit)}</small></strong><span>目标 ${esc(metricOperatorLabel(m.comparison_operator))} ${Number(m.target_value).toLocaleString('zh-CN')} ${esc(m.unit)}</span></div><div class="metric-reference"><span>基准值 <b>${Number(m.baseline_value).toLocaleString('zh-CN')} ${esc(m.unit)}</b></span><span>样本量 <b>${latest?Number(latest.sample_size||0).toLocaleString('zh-CN'):'—'}</b></span></div>${metricTrendSvg(m)}<ul class="metric-history">${history||'<li>暂无周期数据</li>'}</ul><div class="metric-source"><span>来源：${source}</span><span>更新：${latest?formatBusinessDateTime(latest.measured_at):'—'}</span></div>${latest?.methodology?`<details><summary>查看口径说明</summary><p>${esc(latest.methodology)}</p></details>`:''}${isAdmin?`<div class="metric-actions"><button data-edit-metric="${m.id}" data-project="${p.id}">维护定义</button><button data-add-observation="${m.id}" data-project="${p.id}">＋ 新一期</button></div>`:''}</article>`}
function taskRow(t,p){return `<div class="task-row ${!t.done&&t.due<today()?'overdue':''}"><label><input type="checkbox" data-task="${t.id}" data-project="${p.id}" ${t.done?'checked':''} ${isAdmin?'':'disabled'}><span><b>${esc(t.title)}</b><small>${esc(t.priority||'中')}优先 · ${esc(t.owner)} · 截止 ${esc(t.due)}${t.confirmation_status==='pending'?' · 等待确认':''}</small><em>${esc(t.criteria)}</em></span></label>${isAdmin&&t.confirmation_status==='pending'&&!t.done?`<button type="button" data-confirm-task="${t.id}" data-project="${p.id}">确认接单</button>`:''}</div>`}
function thresholdLabel(e){return `${e.threshold_operator} ${Number(e.threshold_value).toLocaleString('zh-CN')} ${esc(e.threshold_unit)}`}
function sourceMarkup(value){const text=esc(value);return /^https?:\/\//i.test(value)?`<a href="${text}" target="_blank" rel="noreferrer">查看数据来源 ↗</a>`:text}
function experimentTimeline(p){return p.experiments.length?p.experiments.map(e=>{const complete=experimentComplete(e),result=e.threshold_met===true?'达标':e.threshold_met===false?'未达标':'待结果',tone=e.threshold_met===true?'passed':e.threshold_met===false?'failed':'';return `<article class="experiment-card ${complete?'completed':'validating'}"><span class="experiment-node"></span><div class="experiment-card-head"><div><span>ROUND ${String(e.round_no).padStart(2,'0')} · ${esc(stages[e.stage])}</span><b>${esc(e.hypothesis)}</b></div><em class="experiment-status ${complete?'done':''}">${complete?'已完成':'验证中'}</em></div><div class="experiment-meta"><span><i>目标用户</i>${esc(e.target_user)}</span><span><i>验证方式</i>${esc(e.method)}</span><span><i>成功阈值</i>${thresholdLabel(e)}</span><span><i>周期</i>${esc(e.start_date)} — ${esc(e.end_date)}</span></div>${complete?`<div class="experiment-result"><div><span class="result-chip ${tone}">${result}</span><b>${Number(e.actual_value).toLocaleString('zh-CN')} ${esc(e.threshold_unit)}</b><small>${esc(e.actual_data)}</small></div><p><i>数据来源</i>${sourceMarkup(e.data_source)}</p><p><i>验证结论</i>${esc(e.conclusion)}</p><p><i>最终决策</i><strong>${esc(e.decision)}</strong></p><p class="learning"><i>关键学习</i>${esc(e.key_learning)}</p></div>`:`<p class="experiment-waiting">实验进行中，结束后填写实际数据、验证结论与最终决策。</p>`}${isAdmin?`<button class="experiment-result-btn" data-experiment-result="${e.id}" data-project="${p.id}">${complete?'维护实验结果':'填写实验结果'} →</button>`:''}</article>`}).join(''):'<p class="empty-inline experiment-empty">暂无验证实验。先把假设、用户、方式和成功阈值写清楚，再开始验证。</p>'}
function gateChecklist(p){const status=gateStatus(p),templateGates=(p.templateGates||[]).filter(g=>g.stage===p.stage),templateDone=templateGates.filter(g=>g.completed).length,total=status.total+templateGates.length,done=status.done+templateDone,missing=advanceRequirements(p);return `<div class="gate-summary"><div><span>${esc(stages[p.stage])}完成度</span><b>${done} / ${total}</b></div><div class="gate-progress"><i style="width:${total?Math.round(done/total*100):0}%"></i></div></div><div class="gate-list">${status.definitions.map(g=>`<label class="gate-item ${status.completed.has(g.gate_key)?'completed':''}"><input type="checkbox" data-gate="${esc(g.gate_key)}" data-stage="${g.stage}" data-project="${p.id}" ${status.completed.has(g.gate_key)?'checked':''} ${isAdmin?'':'disabled'}><span><b>${esc(g.label)}</b><small>${g.required?'必填门槛':'建议门槛'}</small></span></label>`).join('')}${templateGates.map(g=>`<label class="gate-item ${g.completed?'completed':''}"><input type="checkbox" data-template-gate="${g.id}" data-project="${p.id}" ${g.completed?'checked':''} ${isAdmin?'':'disabled'}><span><b>${esc(g.label)}</b><small>模板专属门槛</small></span></label>`).join('')}</div>${missing.length?`<div class="gate-blocker"><b>暂不能推进，还缺少 ${missing.length} 项</b><ul>${missing.map(item=>`<li class="${item.type==='experiment'?'experiment-required':item.type==='metric'?'metric-required':''}">${esc(item.label)}</li>`).join('')}</ul></div>`:'<div class="gate-ready"><b>阶段门槛、验证实验与关键指标均已完成</b><span>可以申请推进至相邻的下一阶段。</span></div>'}`}
function stageTimeline(p){return p.history?.length?p.history.map(h=>{const initial=h.from_stage===null,from=initial?'项目创建':stages[h.from_stage],to=stages[h.to_stage],kind={initial:'创建',advance:'推进',rollback:'回退',cross_stage:'跨阶段'}[h.change_type]||'调整';return `<div class="timeline-item ${h.change_type}"><span class="timeline-dot"></span><div><div class="timeline-top"><b>${esc(kind)} · ${esc(from)}${initial?'':' → '}${initial?'进入 ':''}${esc(to)}</b><time>${formatBusinessDateTime(h.created_at,{month:'numeric',day:'numeric',hour:'2-digit',minute:'2-digit'})}</time></div><p>${esc(h.reason)}</p><small>${esc(h.actor_email)}</small></div></div>`}).join(''):'<p class="empty-inline">暂无阶段历史。</p>'}

function projectTrendCards(p){const related=trendsFor(p.id);return related.length?related.map(t=>{const mapping=t.mappings.find(r=>r.project_id===p.id),source=/^https?:\/\//i.test(t.original_url)?`<a href="${esc(t.original_url)}" target="_blank" rel="noreferrer">查看原始来源 ↗</a>`:'<span class="legacy-source">历史数据未提供原始链接</span>';return `<article class="project-trend-card"><div class="project-trend-head"><div><span>${esc(t.source_platform)} · 发现于 ${esc(t.discovered_on)}</span><b># ${esc(t.name)}</b></div><em>${esc(t.status)}</em></div><div class="project-trend-metrics"><span><i>内容 / 搜索量</i>${esc(t.volume)}</span><span><i>增长率</i>${esc(t.growth)}</span><span><i>可信度</i>${esc(t.confidence)}</span></div><p><i>目标人群</i>${esc(t.target_audience)}</p><p><i>信号说明</i>${esc(t.signal_note)}</p><p class="data-hypothesis"><i>本项目验证假设</i>${esc(mapping?.hypothesis||'待补充')}</p>${source}</article>`}).join(''):'<p class="data-hypothesis">尚未关联趋势；可从“正在验证的趋势”中建立关系。</p>'}

function setBackgroundInert(active){$('main').inert=active;$('.sidebar').inert=active;document.body.classList.toggle('drawer-open',active)}
function focusDrawer(drawer){setTimeout(()=>$('.close-btn',drawer)?.focus(),0)}

function openDrawer(p,returnTarget=null){
  if(!p)return;
  if(!$('#detailDrawer').classList.contains('open'))drawerReturnFocus=returnTarget||document.activeElement;
  const requirements=advanceRequirements(p),stageMarkers=stages.map((name,i)=>`<span class="stage-marker ${i<p.stage?'done':''} ${i===p.stage?'active':''}"><i>${i+1}</i>${esc(name)}</span>`).join(''),health=projectHealth(p),task=nextTask(p),logs=state.activity.filter(a=>a.project_id===p.id||a.text.includes(p.name));
  const overview=`<section class="drawer-block"><div class="drawer-section-head"><h3>项目假设</h3>${isAdmin?`<button data-edit-project="${p.id}">编辑资料</button>`:''}</div><p>${esc(p.intro)}</p><div class="project-taxonomy"><span>${esc(p.category||'未分类')}</span><b>→</b><span>${esc(p.subcategory||'待补充')}</span></div><div class="overview-grid"><span><i>负责人</i>${esc(p.owner)}</span><span><i>参与人员</i>${esc(p.members)}</span><span><i>当前阶段</i>${esc(stages[p.stage])} · ${projectDwell(p)} 天</span><span><i>健康状态</i><b class="health-pill ${healthClass(health)}">${health}</b></span><span class="wide"><i>自动下一步</i>${task?`${esc(task.title)} · ${esc(task.owner)} · ${esc(task.due)}`:'暂无未完成任务'}</span></div></section><section class="drawer-block"><div class="drawer-section-head"><h3>关联趋势</h3><span>${trendsFor(p.id).length} 条</span></div><div class="project-trend-list">${projectTrendCards(p)}</div></section><section class="drawer-block gate-block"><div class="drawer-section-head"><h3>${esc(stages[p.stage])}阶段门槛</h3><span>${p.progress}% 总进度</span></div>${gateChecklist(p)}</section><section class="drawer-block"><h3>项目流转</h3><div class="stage-path">${stageMarkers}</div>${isAdmin?`<div class="stage-action-stack"><button class="primary-btn advance-btn" data-advance="${p.id}" ${p.stage===4||requirements.length?'disabled':''}>${p.stage===4?'已进入最终阶段':requirements.length?`缺少 ${requirements.length} 项推进条件`:'推进至下一阶段 →'}</button><button class="stage-admin-btn" data-admin-stage="${p.id}">管理员回退 / 跨阶段调整</button></div>`:''}</section>`;
  const validation=`<section class="drawer-block experiment-block"><div class="drawer-section-head"><h3>验证实验</h3>${isAdmin?`<button data-add-experiment="${p.id}">＋ 新建一轮</button>`:''}</div><div class="experiment-timeline">${experimentTimeline(p)}</div></section><section class="drawer-block"><div class="drawer-section-head"><h3>结构化验证指标</h3>${isAdmin?`<button data-add-metric="${p.id}">＋ 添加</button>`:''}</div><div class="metric-data-list">${p.metrics.length?p.metrics.map(m=>metricCard(m,p)).join(''):'<p class="empty-inline">尚未录入验证指标。</p>'}</div></section>`;
  const groups=[['待办',p.tasks.filter(t=>!t.done&&t.due>=today())],['逾期',p.tasks.filter(t=>!t.done&&t.due<today())],['已完成',p.tasks.filter(t=>t.done)]];const tasks=`<section class="drawer-block"><div class="drawer-section-head"><h3>项目任务</h3>${isAdmin?`<button data-add-task="${p.id}">＋ 添加</button>`:''}</div>${groups.map(([name,items])=>`<div class="task-group"><h4>${name} <span>${items.length} 项</span></h4><div class="task-list">${items.length?items.map(t=>taskRow(t,p)).join(''):'<p class="empty-inline">暂无</p>'}</div></div>`).join('')}</section>`;
  const records=`<section class="drawer-block"><h3>阶段变化</h3><div class="stage-timeline">${stageTimeline(p)}</div></section><section class="drawer-block"><h3>资料、决策与操作日志</h3><div class="activity-list">${logs.map(a=>`<p><time>${formatBusinessDateTime(a.created_at)}</time><b>${esc(a.type)}</b>${esc(a.text)}<small>${esc(a.actor_email||'system')}</small></p>`).join('')||'<p>暂无记录。</p>'}</div></section>`;
  $('#drawerEyebrow').innerHTML=`${esc(stages[p.stage])} · 停留 ${projectDwell(p)} 天 · <span class="health-pill ${healthClass(health)}">${health}</span>`;$('#drawerTitle').textContent=p.name;
  $('#drawerContent').innerHTML=`<div class="drawer-primary-actions">${isAdmin?`<button data-edit-project="${p.id}">编辑</button><button data-add-task="${p.id}">＋ 任务</button>${p.stage===4?`<button data-extract-template="${p.id}">提炼模板</button>`:''}`:'<span>公开只读</span>'}</div><nav class="drawer-tabs" aria-label="项目详情标签">${[['overview','概览'],['validation','验证实验'],['tasks','任务'],['records','记录']].map(([id,label])=>`<button type="button" data-drawer-tab="${id}" class="${activeDrawerTab===id?'active':''}">${label}</button>`).join('')}</nav><div class="drawer-tab-panel" data-tab-panel="overview" ${activeDrawerTab==='overview'?'':'hidden'}>${overview}</div><div class="drawer-tab-panel" data-tab-panel="validation" ${activeDrawerTab==='validation'?'':'hidden'}>${validation}</div><div class="drawer-tab-panel" data-tab-panel="tasks" ${activeDrawerTab==='tasks'?'':'hidden'}>${tasks}</div><div class="drawer-tab-panel" data-tab-panel="records" ${activeDrawerTab==='records'?'':'hidden'}>${records}</div>${isAdmin?`<div class="drawer-actions"><button class="danger-btn" data-delete-project="${p.id}">删除项目</button></div>`:''}`;
  $('#detailDrawer').classList.add('open');$('#drawerOverlay').classList.add('open');$('#detailDrawer').setAttribute('aria-hidden','false');setBackgroundInert(true);focusDrawer($('#detailDrawer'));
}

function closeDrawer(){const wasOpen=$('#detailDrawer').classList.contains('open');$('#detailDrawer').classList.remove('open');$('#drawerOverlay').classList.remove('open');$('#detailDrawer').setAttribute('aria-hidden','true');if(wasOpen){setBackgroundInert(false);drawerReturnFocus?.focus();drawerReturnFocus=null}}
function setStage(stage){selectedStage=stage;const tabs=$$('.stage-tab');tabs.forEach((tab,index)=>{const active=tab.dataset.stage===String(stage);tab.classList.toggle('active',active);tab.setAttribute('role','tab');tab.setAttribute('aria-selected',String(active));tab.setAttribute('aria-controls','projectRows');tab.tabIndex=active||stage==='all'&&index===0?0:-1});const all=stage==='all';$('#allStages').classList.toggle('active',all);$('#allStages').setAttribute('aria-pressed',String(all));renderProjects()}
function renderStageDialogState(){const p=project(pendingProject);if(!p)return;const target=pendingStageMode==='admin'?Number($('#stageTarget').value):pendingStage,delta=target-p.stage,forward=delta>0,missing=forward?advanceRequirements(p):[],reasonRequired=delta<0||Math.abs(delta)>1;pendingStage=target;$('#advanceTitle').textContent=`${delta<0?'回退':delta>1?'跨阶段调整':'推进'}至「${stages[target]}」` ;$('#advanceCopy').textContent=`「${p.name}」将从「${stages[p.stage]}」调整至「${stages[target]}」。本次变更会写入不可变更的阶段历史。`;$('#stageReasonLabel').textContent=reasonRequired?'调整原因（必填）':'推进说明（选填）';$('#stageReason').required=reasonRequired;$('#stageReasonHint').textContent=reasonRequired?'回退或跨阶段调整必须说明依据与后续处理。':'不填写时，将记录为“阶段门槛、验证实验与关键指标均已完成”。';$('#stageGateSummary').innerHTML=missing.length?`<div class="stage-dialog-blocked"><b>无法进入后续阶段，还缺少：</b><ul>${missing.map(item=>`<li>${esc(item.label)}</li>`).join('')}</ul></div>`:'<div class="stage-dialog-ready">阶段门槛、验证实验与关键指标检查通过</div>';$('#stageSubmit').disabled=Boolean(missing.length);$('#stageSubmit').textContent=missing.length?'推进条件未完成':delta<0?'确认回退 →':delta>1?'确认跨阶段调整 →':'确认推进 →'}
function requestStage(projectId,target,mode='advance'){if(!requireAdmin())return;const p=project(projectId);if(!p)return;pendingProject=projectId;pendingStageMode=mode;$('#advanceForm').reset();const admin=mode==='admin';$('#stageTargetWrap').hidden=!admin;if(admin){const options=stages.map((name,i)=>({name,i})).filter(x=>x.i!==p.stage&&x.i!==p.stage+1);if(!options.length){notice('当前没有可用的回退或跨阶段目标。');return}$('#stageTarget').innerHTML=options.map(x=>`<option value="${x.i}">${x.i<p.stage?'回退':'跨阶段'} · ${x.name}</option>`).join('');pendingStage=options[0].i}else{pendingStage=target;if(target!==p.stage+1){notice('默认推进只能进入相邻的下一阶段。');return}}renderStageDialogState();$('#advanceDialog').showModal()}

function populateCategories(){const select=$('#projectCategory');select.innerHTML=`<option value="">选择一级类别</option>${Object.keys(appCategories).map(name=>`<option value="${name}">${name}</option>`).join('')}`}
