function renderTrendProjectPicker(t=null){$('#trendProjects').innerHTML=state.projects.map(p=>{const mapping=t?.mappings.find(r=>r.project_id===p.id),checked=Boolean(mapping);return `<div class="project-pick ${checked?'selected':''}" data-picker-project="${p.id}"><label><input type="checkbox" ${checked?'checked':''}><span><b>${esc(p.name)}</b><small>${esc(p.category)} / ${esc(p.subcategory)}</small></span></label><textarea rows="2" placeholder="该项目准备如何利用并验证这条趋势" ${checked?'required':'disabled'}>${esc(mapping?.hypothesis||'')}</textarea></div>`}).join('')||'<p class="empty-inline">请先创建项目，再建立趋势关系。</p>'}
function fillTrendForm(trendId=''){const t=state.trends.find(item=>item.id===trendId)||null;$('#trendExisting').value=t?.id||'';$('#trendDialogTitle').textContent=t?'维护趋势与项目关系':'建立趋势与项目关系';$('#trendSubmit').textContent=t?'保存趋势与关联 →':'创建趋势并关联 →';$('#trendName').value=t?.name||'';ensureSelectValue($('#trendPlatform'),t?.source_platform||'');$('#trendUrl').value=t?.original_url||'';$('#trendDiscovered').value=t?.discovered_on||today();$('#trendVolume').value=t?.volume==='待录入'?'':t?.volume||'';$('#trendGrowth').value=t?.growth==='待录入'?'':t?.growth||'';$('#trendAudience').value=t?.target_audience==='待补充'?'':t?.target_audience||'';$('#trendSignal').value=t?.signal_note==='待补充'?'':t?.signal_note||'';ensureSelectValue($('#trendConfidence'),t?.confidence||'');ensureSelectValue($('#trendStatus'),t?.status||'');renderTrendProjectPicker(t)}
