function localDateTime(date=new Date()){const parts=new Intl.DateTimeFormat('en-CA',{timeZone:BUSINESS_TIME_ZONE,year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',hourCycle:'h23'}).formatToParts(date),v=Object.fromEntries(parts.filter(p=>p.type!=='literal').map(p=>[p.type,p.value]));return `${v.year}-${v.month}-${v.day}T${v.hour}:${v.minute}`}
function toggleInitialObservation(show){$('#metricInitialObservation').hidden=!show;$$('input,textarea,select',$('#metricInitialObservation')).forEach(node=>node.disabled=!show)}
function openMetric(projectId,metricId=''){if(!requireAdmin())return;const p=project(projectId),m=metricId?p.metrics.find(x=>x.id===metricId):null;$('#metricForm').reset();$('#metricProjectId').value=projectId;$('#metricIndex').value=metricId;$('#metricDialogTitle').textContent=m?'维护指标定义':'添加结构化指标';$('#metricStageNote').textContent=m?'维护单位、目标和关键属性；历史周期数据不会被覆盖。':`指标默认归属当前「${stages[p.stage]}」阶段，并保存首期观测数据。`;$('#metricName').value=m?.name||'';$('#metricUnit').value=m?.unit||'';$('#metricBaseline').value=m?.baseline_value??'';$('#metricTarget').value=m?.target_value??'';$('#metricOperator').value=m?.comparison_operator||'>=';$('#metricStage').innerHTML=stages.map((name,i)=>`<option value="${i}">${i+1}. ${name}</option>`).join('');$('#metricStage').value=String(m?.stage??p.stage);$('#metricIsKey').checked=Boolean(m?.is_key);toggleInitialObservation(!m);if(!m){$('#metricPeriodStart').value=today();$('#metricPeriodEnd').value=today();$('#metricMeasuredAt').value=localDateTime()}$('#metricSubmit').textContent=m?'保存指标定义 →':'创建指标并保存首期数据 →';$('#metricDialog').showModal()}
function openMetricObservation(projectId,metricId){if(!requireAdmin())return;const p=project(projectId),m=p?.metrics.find(item=>item.id===metricId),latest=m&&latestObservation(m);if(!m)return;$('#metricObservationForm').reset();$('#metricObservationProjectId').value=p.id;$('#metricObservationMetricId').value=m.id;$('#metricObservationTitle').textContent=`录入「${m.name}」新一期数据`;$('#metricObservationContext').textContent=`单位 ${m.unit} · 目标 ${metricOperatorLabel(m.comparison_operator)} ${Number(m.target_value).toLocaleString('zh-CN')} ${m.unit}`;$('#observationPeriodStart').value=today();$('#observationPeriodEnd').value=today();$('#observationMeasuredAt').value=localDateTime();$('#observationSourceName').value=latest?.source_name||'';$('#observationSourceUrl').value=latest?.source_url||'';$('#observationMethodology').value=latest?.methodology||'';$('#metricObservationDialog').showModal()}
