function lines(value){return String(value||'').split('\n').map(v=>v.trim()).filter(Boolean)}
function openTemplateDialog(sourceProjectId=''){if(!requireAdmin())return;const p=project(sourceProjectId);$('#templateForm').reset();$('#templateSourceProject').value=sourceProjectId;$('#templateDialogTitle').textContent=p?`从「${p.name}」提炼模板`:'新建验证模板';if(p){$('#templateName').value=`${p.category||'项目'}验证模板`;$('#templateOpportunity').value=p.subcategory||p.category||'';$('#templateAudience').value=trendsFor(p.id).map(t=>t.target_audience).filter(Boolean).join('；')||'待补充目标用户';$('#templateHypotheses').value=p.experiments.map(e=>e.hypothesis).join('\n')||p.intro;$('#templateMethods').value=[...new Set(p.experiments.map(e=>e.method))].join('\n')||'用户访谈 / 问卷';$('#templateGates').value=state.gateDefinitions.map(g=>`${stages[g.stage]} | ${g.label}`).join('\n');$('#templateMetrics').value=p.metrics.map(m=>`${m.name} | ${m.unit} | ${m.comparison_operator} | ${m.target_value} | ${m.stage}`).join('\n')||'核心转化率 | % | >= | 10 | 2';$('#templateThresholds').value=p.experiments.map(e=>`${e.hypothesis}：${e.threshold_operator} ${e.threshold_value} ${e.threshold_unit}`).join('\n')||'关键指标达到设定目标';$('#templateCycle').value=`${Math.max(1,Math.ceil(daysBetween(p.created_at)/7))} 周`;$('#templateTasks').value=p.tasks.map(t=>`${t.title} | ${t.stage||0} | 7 | ${t.priority||'中'}`).join('\n')||'完成首轮用户验证 | 0 | 7 | 高';$('#templateFailures').value=p.experiments.filter(e=>e.threshold_met===false).map(e=>e.key_learning||e.conclusion).join('\n')||'样本不足\n信号与目标用户不匹配'}$('#templateDialog').showModal()}
function openExperiment(projectId){if(!requireAdmin())return;const p=project(projectId);$('#experimentForm').reset();$('#experimentProjectId').value=p.id;$('#experimentMethod').innerHTML=experimentMethods.map(name=>`<option value="${name}">${name}</option>`).join('');$('#experimentStart').value=today();$('#experimentEnd').value=shiftDayKey(today(),7);$('#experimentDialogTitle').textContent=`新建第 ${p.experiments.length+1} 轮验证实验`;$('#experimentStageNote').textContent=`本轮固定归属「${stages[p.stage]}」阶段`;$('#experimentDialog').showModal()}
function openExperimentResult(projectId,experimentId){if(!requireAdmin())return;const p=project(projectId),e=p.experiments.find(item=>item.id===experimentId);if(!e)return;$('#experimentResultForm').reset();$('#experimentResultProjectId').value=p.id;$('#experimentResultId').value=e.id;$('#experimentResultTitle').textContent=`第 ${e.round_no} 轮实验结果`;$('#experimentResultHypothesis').textContent=e.hypothesis;$('#experimentResultThreshold').textContent=`成功阈值 ${e.threshold_operator} ${Number(e.threshold_value).toLocaleString('zh-CN')} ${e.threshold_unit}`;$('#experimentActualValue').value=e.actual_value??'';$('#experimentActualData').value=e.actual_data||'';$('#experimentDataSource').value=e.data_source||'';$('#experimentConclusion').value=e.conclusion||'';$('#experimentDecision').innerHTML=`<option value="">选择最终决策</option>${experimentDecisions.map(name=>`<option value="${name}">${name}</option>`).join('')}`;$('#experimentDecision').value=e.decision||'';$('#experimentLearning').value=e.key_learning||'';renderExperimentPreview();$('#experimentResultDialog').showModal()}
function compareThreshold(actual,operator,target){return operator==='>='?actual>=target:operator==='>'?actual>target:operator==='<='?actual<=target:operator==='<'?actual<target:actual===target}
function renderExperimentPreview(){const p=project($('#experimentResultProjectId').value),e=p?.experiments.find(item=>item.id===$('#experimentResultId').value),raw=$('#experimentActualValue').value,node=$('#experimentAutoResult');if(!e||raw===''){node.textContent='输入实际数值后，系统将自动判断是否达到成功阈值。';node.className='experiment-auto-result';return}const actual=Number(raw),met=compareThreshold(actual,e.threshold_operator,Number(e.threshold_value));node.textContent=met?`自动判断：已达到成功阈值（${actual} ${e.threshold_unit}）`:`自动判断：未达到成功阈值（${actual} ${e.threshold_unit}）`;node.className=`experiment-auto-result ${met?'passed':'failed'}`}
function showDataGuide(){const grid=$('.data-guide-grid'),riskCard=[...grid.children].find(card=>$('h3',card)?.textContent==='风险项目');if(riskCard)$('p',riskCard).textContent='实时汇总逾期、即将到期、待确认、阶段超时、指标未达标、数据来源缺失和待管理层决策；项目数与具体问题数分开统计。';if(!$('.data-guide-extra',grid))grid.insertAdjacentHTML('beforeend','<article class="data-guide-extra"><h3>结构化指标</h3><p>指标定义与多期观测分开保存，数值、单位、样本量和来源均为独立字段；状态实时计算，关键指标未达标会阻止推进。</p></article><article class="data-guide-extra"><h3>验证模板</h3><p>模板创建项目时生成专属阶段门槛、推荐指标与标准任务；使用次数、来源项目和最终成功率均实时追溯。</p></article><article class="data-guide-extra"><h3>周期、单位与时区</h3><p>项目使用“个”、趋势使用“条”、验证使用“轮”、风险分别展示项目数与问题数、任务使用“项”；全部周期和逾期判断采用配置的业务时区。</p></article>');const list=state.activity.slice(0,8).map(a=>`<p><b>${esc(a.at)}</b><span>${esc(a.type)} · ${esc(a.text)}</span></p>`).join('');$('#dataLog').innerHTML=`<h3>最近线上记录</h3>${list||'<p>暂无记录</p>'}`;renderTrash();$('#dataDialog').showModal()}
function syncFilterUrl(){const params=new URLSearchParams();if(searchTerm)params.set('q',searchTerm);Object.entries(projectFilters).forEach(([key,value])=>{if(value&&(key!=='sort'||value!=='updated'))params.set(key,value)});if(selectedStage!=='all')params.set('funnel',selectedStage);if(selectedTrend)params.set('trend',selectedTrend);history.replaceState(null,'',`${location.pathname}${params.toString()?`?${params}`:''}${location.hash||'#projects'}`)}
function restoreFilters(){const params=new URLSearchParams(location.search);searchTerm=params.get('q')||'';$('#projectSearch').value=searchTerm;Object.keys(projectFilters).forEach(key=>{projectFilters[key]=params.get(key)||projectFilters[key]});selectedStage=params.get('funnel')||'all';selectedTrend=params.get('trend')||'';['category','stage','owner','health','flag','sort'].forEach(key=>{const node=$(`#${key==='sort'?'projectSort':`filter${key[0].toUpperCase()}${key.slice(1)}`}`);if(node)node.value=projectFilters[key]})}

