$('#projectForm').addEventListener('submit',async e=>{e.preventDefault();const form=e.currentTarget,id=$('#editProjectId').value,name=$('#newProjectName').value.trim(),intro=$('#newProjectIntro').value.trim(),category=$('#projectCategory').value,subcategory=$('#projectSubcategory').value,owner=$('#projectOwner').value.trim(),members=$('#projectMembers').value.trim();if(!name||!intro||!category||!subcategory||!owner||!members)return;setBusy(form,true);let savedId=id;const ok=await mutate(async()=>{if(id){const {error}=await db.from('projects').update({name,intro,category,subcategory,owner,members}).eq('id',id);if(error)throw error;await writeLog(id,`更新项目「${name}」的资料与分类`,'项目编辑')}else if(selectedTemplate){const {data,error}=await db.rpc('create_project_from_template',{p_template_id:selectedTemplate,p_name:name,p_intro:intro,p_category:category,p_subcategory:subcategory,p_owner:owner,p_members:members});if(error)throw error;savedId=data}else{const {data:p,error}=await db.from('projects').insert({name,intro,category,subcategory,owner,members}).select().single();if(error)throw error;savedId=p.id;await writeLog(p.id,`创建项目「${name}」，归类为「${category} / ${subcategory}」`,'新增')}},id?'项目资料已保存。':selectedTemplate?`「${name}」已从模板创建，门槛、指标与任务已生成。`:`「${name}」已立项，可继续建立趋势映射。`);setBusy(form,false);if(ok){selectedTemplate='';$('#projectDialog').close();form.reset();setSubcategories('');setStage(id?selectedStage:'0');const saved=project(savedId)||state.projects.find(p=>p.name===name);if(saved)openDrawer(saved)}});

