document.addEventListener('keydown',e=>{const drawer=$('.detail-drawer.open');if(e.key==='Escape'){if($('#riskDrawer').classList.contains('open'))closeRiskCenter();else closeDrawer();return}if(e.key!=='Tab'||!drawer)return;const focusable=$$('button,[href],input,select,textarea,[tabindex]:not([tabindex="-1"])',drawer).filter(el=>!el.disabled&&!el.hidden&&el.offsetParent!==null);if(!focusable.length)return;const first=focusable[0],last=focusable.at(-1);if(e.shiftKey&&document.activeElement===first){e.preventDefault();last.focus()}else if(!e.shiftKey&&document.activeElement===last){e.preventDefault();first.focus()}});

async function initialize(){
  populateCategories();
  if(!db){setSync('线上配置缺失','error');renderAll();return}
  const {data}=await db.auth.getSession();currentUser=data.session?.user||null;renderAuth();
  db.auth.onAuthStateChange((_event,session)=>{currentUser=session?.user||null;renderAuth()});
  await loadData();
  restoreFilters();setStage(selectedStage);renderProjects();renderTrends();
  realtimeChannel=db.channel('company-project-board-live').on('postgres_changes',{event:'*',schema:'public'},()=>{clearTimeout(reloadTimer);reloadTimer=setTimeout(()=>loadData({quiet:true}),350)}).subscribe(status=>{if(status==='CHANNEL_ERROR')setSync('实时连接中断','error')});
}

initialize();
